// ========================================
// WF3 v3 - GROUP BY RECIPIENT + NOTION MESSAGES
// Fixed: CC/BCC properly passed to Gmail node
// Updated: 28/12/2025
// ========================================

var tasksResponse = $('Query Active Tasks').first().json;
var messagesResponse = $('Query Message Library').first().json;

var allTasks = tasksResponse.results || [];
var allMessages = messagesResponse.results || [];

var today = new Date();
var dayOfWeek = today.getDay();

// ========== PARSE MESSAGES BY CATEGORY ==========
var messagesByCategory = {};

for (var i = 0; i < allMessages.length; i++) {
  var msg = allMessages[i];
  var props = msg.properties || {};

  var category = '';
  if (props.Category && props.Category.select) {
    category = props.Category.select.name;
  }

  var content = '';
  if (props['Nội dung'] && props['Nội dung'].title && props['Nội dung'].title[0]) {
    content = props['Nội dung'].title[0].plain_text;
  }

  var usedCount = 0;
  if (props['Used Count'] && props['Used Count'].number !== null) {
    usedCount = props['Used Count'].number;
  }

  if (category && content) {
    if (!messagesByCategory[category]) {
      messagesByCategory[category] = [];
    }
    messagesByCategory[category].push({
      id: msg.id,
      content: content,
      usedCount: usedCount
    });
  }
}

// Function: Get random message (prefer less used)
function getRandomMsg(cat) {
  var msgs = messagesByCategory[cat];
  if (!msgs || msgs.length === 0) {
    return { content: '', id: null };
  }

  msgs.sort(function(a, b) { return a.usedCount - b.usedCount; });
  var poolSize = Math.min(3, msgs.length);
  var pool = msgs.slice(0, poolSize);
  var picked = pool[Math.floor(Math.random() * pool.length)];

  return picked;
}

// ========== GROUP TASKS BY RECIPIENT ==========
var tasksByRecipient = {};

for (var j = 0; j < allTasks.length; j++) {
  var task = allTasks[j];
  var tProps = task.properties || {};

  // Get title
  var title = '';
  for (var k1 in tProps) {
    if (tProps[k1].type === 'title' && tProps[k1].title && tProps[k1].title[0]) {
      title = tProps[k1].title[0].plain_text || '';
      break;
    }
  }

  // Get deadline
  var deadline = null;
  var deadlineStr = '';
  for (var k2 in tProps) {
    var k2Lower = k2.toLowerCase();
    if (k2Lower.indexOf('thời hạn') !== -1 || k2Lower.indexOf('t4') !== -1) {
      if (tProps[k2].date && tProps[k2].date.start) {
        deadline = new Date(tProps[k2].date.start);
        deadlineStr = tProps[k2].date.start;
      }
      break;
    }
  }

  // Get recipient email
  var recipientEmail = '';
  var recipientName = '';

  for (var k3 in tProps) {
    var k3Lower = k3.toLowerCase();
    if (k3Lower.indexOf('người nhận') !== -1 || k3Lower.indexOf('đầu mối') !== -1 || k3Lower.indexOf('assignee') !== -1 || k3Lower.indexOf('email') !== -1) {
      var prop = tProps[k3];

      if (prop.type === 'people' && prop.people && prop.people[0]) {
        if (prop.people[0].person && prop.people[0].person.email) {
          recipientEmail = prop.people[0].person.email;
        }
        recipientName = prop.people[0].name || '';
      }

      if (prop.type === 'email' && prop.email) {
        recipientEmail = prop.email;
      }

      if (prop.type === 'rich_text' && prop.rich_text && prop.rich_text[0]) {
        var txt = prop.rich_text[0].plain_text || '';
        if (txt.indexOf('@') !== -1) {
          recipientEmail = txt.trim();
        }
      }

      if (recipientEmail) break;
    }
  }

  if (!recipientEmail) continue;

  // Calculate days left
  var daysLeft = null;
  var status = 'normal';
  if (deadline) {
    daysLeft = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));
    if (daysLeft < 0) status = 'overdue';
    else if (daysLeft <= 1) status = 'today';
    else if (daysLeft <= 3) status = 'soon';
  }

  if (!tasksByRecipient[recipientEmail]) {
    tasksByRecipient[recipientEmail] = {
      email: recipientEmail,
      name: recipientName,
      tasks: [],
      hasOverdue: false,
      hasDueSoon: false
    };
  }

  tasksByRecipient[recipientEmail].tasks.push({
    id: task.id,
    title: title,
    deadline: deadlineStr,
    daysLeft: daysLeft,
    status: status,
    url: task.url || 'https://www.notion.so/' + task.id.replace(/-/g, '')
  });

  if (status === 'overdue') tasksByRecipient[recipientEmail].hasOverdue = true;
  if (status === 'soon' || status === 'today') tasksByRecipient[recipientEmail].hasDueSoon = true;
}

// ========== BUILD OUTPUT ==========
var results = [];

for (var email in tasksByRecipient) {
  var r = tasksByRecipient[email];

  var greeting = getRandomMsg('greeting');
  var intro, subjectMsg;

  if (r.hasOverdue) {
    intro = getRandomMsg('intro_overdue');
    subjectMsg = getRandomMsg('subject_overdue');
  } else if (r.hasDueSoon) {
    intro = getRandomMsg('intro_deadline');
    subjectMsg = getRandomMsg('subject_deadline');
  } else {
    intro = getRandomMsg('intro_progress');
    subjectMsg = getRandomMsg('subject_progress');
  }

  var offerHelp = getRandomMsg('offer_help');
  var closing = (dayOfWeek === 5) ? getRandomMsg('closing_friday') : getRandomMsg('closing');

  // Build task HTML
  var taskHtml = '';
  for (var m = 0; m < r.tasks.length; m++) {
    var t = r.tasks[m];
    var icon = '🟢';
    var statusTxt = '';

    if (t.status === 'overdue') {
      icon = '🔴';
      statusTxt = ' (quá hạn ' + Math.abs(t.daysLeft) + ' ngày)';
    } else if (t.status === 'today') {
      icon = '🟠';
      statusTxt = ' (hôm nay)';
    } else if (t.status === 'soon') {
      icon = '🟡';
      statusTxt = ' (còn ' + t.daysLeft + ' ngày)';
    }

    taskHtml += '<tr style="border-bottom:1px solid #eee;">';
    taskHtml += '<td style="padding:12px;font-size:20px;text-align:center;">' + icon + '</td>';
    taskHtml += '<td style="padding:12px;"><a href="' + t.url + '" style="color:#2c3e50;text-decoration:none;font-weight:500;">' + t.title + '</a><span style="color:#e74c3c;font-size:13px;">' + statusTxt + '</span></td>';
    taskHtml += '<td style="padding:12px;color:#7f8c8d;font-size:13px;">' + (t.deadline || 'Chưa có') + '</td>';
    taskHtml += '</tr>';
  }

  results.push({
    recipientEmail: email,
    recipientName: r.name || email.split('@')[0],
    ccEmails: 'leson@esuhai.com, hoangkha@esuhai.com',
    bccEmails: 'chatlong@esuhai.com',
    subject: subjectMsg.content || '[Phối hợp] Cập nhật tiến độ công việc',
    greeting: greeting.content || 'Anh/chị ơi,',
    intro: intro.content || 'Em đang tổng hợp tiến độ, nhờ anh/chị hỗ trợ cập nhật ạ.',
    offerHelp: offerHelp.content || 'Nếu có gì cần phối hợp, anh/chị cứ nói em nhé.',
    closing: closing.content || 'Cảm ơn anh/chị!',
    taskCount: r.tasks.length,
    hasOverdue: r.hasOverdue,
    hasDueSoon: r.hasDueSoon,
    taskListHtml: taskHtml
  });
}

if (results.length === 0) {
  return [{ json: { shouldSend: false, message: 'Không có task nào cần gửi' } }];
}

return results.map(function(item) { return { json: item }; });
